class PCIComplianceManager {
  static final PCIComplianceManager _instance = PCIComplianceManager._internal();
  factory PCIComplianceManager() => _instance;
  PCIComplianceManager._internal();

  String tokenizeCardData({
    required String cardNumber,
    required String cvv,
    required String expiryMonth,
    required String expiryYear,
  }) {
    _validateCardNumber(cardNumber);
    _validateCVV(cvv);
    _validateExpiry(expiryMonth, expiryYear);

    final dataToHash = '$cardNumber|$cvv|$expiryMonth/$expiryYear|${DateTime.now().millisecondsSinceEpoch}';
    final bytes = utf8.encode(dataToHash);
    final digest = sha256.convert(bytes);
    return 'tok_${digest.toString().substring(0, 32)}';
  }

  String maskCardNumber(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 4) return '****';
    return '**** **** **** ${cleaned.substring(cleaned.length - 4)}';
  }

  void _validateCardNumber(String number) {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) {
      throw PaymentException('Invalid card number length', code: 'INVALID_CARD');
    }
    if (!_luhnCheck(cleaned)) {
      throw PaymentException('Invalid card number', code: 'INVALID_CARD');
    }
  }

  void _validateCVV(String cvv) {
    if (cvv.length < 3 || cvv.length > 4) {
      throw PaymentException('Invalid CVV', code: 'INVALID_CVV');
    }
    if (!RegExp(r'^\d+$').hasMatch(cvv)) {
      throw PaymentException('CVV must be numeric', code: 'INVALID_CVV');
    }
  }

  void _validateExpiry(String month, String year) {
    final m = int.tryParse(month);
    final y = int.tryParse(year);
    if (m == null || y == null || m < 1 || m > 12) {
      throw PaymentException('Invalid expiry date', code: 'INVALID_EXPIRY');
    }
    final fullYear = y < 100 ? 2000 + y : y;
    final expiry = DateTime(fullYear, m + 1, 0);
    if (expiry.isBefore(DateTime.now())) {
      throw PaymentException('Card has expired', code: 'CARD_EXPIRED');
    }
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  String detectCardBrand(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.startsWith('4')) return 'Visa';
    if (RegExp(r'^5[1-5]').hasMatch(cleaned)) return 'Mastercard';
    if (RegExp(r'^3[47]').hasMatch(cleaned)) return 'Amex';
    if (RegExp(r'^6(?:011|5)').hasMatch(cleaned)) return 'Discover';
    if (RegExp(r'^35(?:2[89]|[3-8])').hasMatch(cleaned)) return 'JCB';
    if (RegExp(r'^3(?:0[0-5]|[68])').hasMatch(cleaned)) return 'Diners';
    return 'Unknown';
  }

  Map<String, dynamic> sanitizeForLogging(Map<String, dynamic> data) {
    final sanitized = Map<String, dynamic>.from(data);
    const sensitiveKeys = ['card_number', 'cvv', 'cvc', 'security_code', 'password', 'secret'];
    for (final key in sensitiveKeys) {
      if (sanitized.containsKey(key)) {
        sanitized[key] = '***REDACTED***';
      }
    }
    return sanitized;
  }
}

class EncryptionService {
  static final EncryptionService _instance = EncryptionService._internal();
  factory EncryptionService() => _instance;
  EncryptionService._internal();

  String encryptPayload(Map<String, dynamic> payload, String encryptionKey) {
    final jsonString = jsonEncode(payload);
    final keyBytes = utf8.encode(encryptionKey);
    final dataBytes = utf8.encode(jsonString);

    final hmacSha256 = Hmac(sha256, keyBytes);
    final digest = hmacSha256.convert(dataBytes);

    final combined = {
      'data': base64Encode(dataBytes),
      'signature': digest.toString(),
      'timestamp': DateTime.now().millisecondsSinceEpoch,
    };

    return base64Encode(utf8.encode(jsonEncode(combined)));
  }

  bool verifySignature(String encryptedPayload, String encryptionKey) {
    try {
      final decoded = utf8.decode(base64Decode(encryptedPayload));
      final combined = jsonDecode(decoded) as Map<String, dynamic>;

      final data = base64Decode(combined['data'] as String);
      final signature = combined['signature'] as String;

      final keyBytes = utf8.encode(encryptionKey);
      final hmacSha256 = Hmac(sha256, keyBytes);
      final digest = hmacSha256.convert(data);

      return digest.toString() == signature;
    } catch (_) {
      return false;
    }
  }

  String generateIdempotencyKey() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = DateTime.now().microsecond;
    final data = '$timestamp-$random';
    final bytes = utf8.encode(data);
    final digest = sha256.convert(bytes);
    return 'idem_${digest.toString().substring(0, 24)}';
  }
}

