class StripeGateway implements PaymentGateway {
  final PaymentConfig config;
  final PCIComplianceManager _pci = PCIComplianceManager();
  final EncryptionService _encryption = EncryptionService();
  final PaymentLogger _logger;

  StripeGateway({required this.config}) : _logger = PaymentLogger(enabled: config.enableLogging);

  @override
  Future<TransactionResult> processPayment({
    required double amount,
    required String currency,
    required PaymentMethod method,
    required Map<String, dynamic> paymentDetails,
    String? idempotencyKey,
  }) async {
    final idemKey = idempotencyKey ?? _encryption.generateIdempotencyKey();

    _logger.log('Processing payment: amount=$amount, currency=$currency, method=${method.name}');

    try {
      _validateAmount(amount);
      _validateCurrency(currency);

      final paymentIntentId = await createPaymentIntent(
        amount: amount,
        currency: currency,
        metadata: {'method': method.name, 'idempotency_key': idemKey},
      );

      // Simulate gateway processing
      await Future.delayed(const Duration(milliseconds: 500));

      final result = TransactionResult(
        transactionId: paymentIntentId,
        status: TransactionStatus.completed,
        amount: amount,
        currency: currency,
        method: method,
        timestamp: DateTime.now(),
        receiptUrl: '${config.apiBaseUrl}/receipts/$paymentIntentId',
        metadata: {
          'idempotency_key': idemKey,
          'gateway': 'stripe',
          'sandbox': config.sandboxMode,
        },
      );

      _logger.log('Payment successful: ${result.transactionId}');
      return result;
    } on PaymentException {
      rethrow;
    } catch (e) {
      _logger.error('Payment processing failed: $e');
      return TransactionResult(
        transactionId: 'failed_${DateTime.now().millisecondsSinceEpoch}',
        status: TransactionStatus.failed,
        amount: amount,
        currency: currency,
        method: method,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
        errorCode: 'PROCESSING_ERROR',
      );
    }
  }

  @override
  Future<TransactionResult> refundPayment({
    required String transactionId,
    required double amount,
    String? reason,
  }) async {
    _logger.log('Processing refund for $transactionId: amount=$amount');

    try {
      _validateAmount(amount);

      // Simulate refund processing
      await Future.delayed(const Duration(milliseconds: 300));

      final refundId = 'ref_${DateTime.now().millisecondsSinceEpoch}';

      return TransactionResult(
        transactionId: refundId,
        status: TransactionStatus.refunded,
        amount: amount,
        currency: 'USD',
        method: PaymentMethod.creditCard,
        timestamp: DateTime.now(),
        metadata: {
          'original_transaction': transactionId,
          'reason': reason,
        },
      );
    } catch (e) {
      _logger.error('Refund failed: $e');
      throw PaymentException('Refund failed: $e', code: 'REFUND_ERROR');
    }
  }

  @override
  Future<String> createPaymentIntent({
    required double amount,
    required String currency,
    Map<String, dynamic>? metadata,
  }) async {
    final amountInCents = (amount * 100).round();

    final payload = {
      'amount': amountInCents,
      'currency': currency.toLowerCase(),
      'merchant_id': config.merchantId,
      'metadata': metadata,
      'timestamp': DateTime.now().toIso8601String(),
    };

    final encryptedPayload = _encryption.encryptPayload(payload, config.stripeSecretKey);

    _logger.log('Created payment intent for $amountInCents cents $currency');

    // In production, this would make an API call to your backend
    // which then communicates with Stripe's API
    return 'pi_${sha256.convert(utf8.encode(encryptedPayload)).toString().substring(0, 24)}';
  }

  @override
  Future<bool> verifyPayment(String transactionId) async {
    _logger.log('Verifying payment: $transactionId');

    // In production, verify with Stripe API via your backend
    await Future.delayed(const Duration(milliseconds: 200));

    return transactionId.startsWith('pi_') || transactionId.startsWith('ref_');
  }

  @override
  Future<PaymentCard> tokenizeCard({
    required String cardNumber,
    required String cvv,
    required String expiryMonth,
    required String expiryYear,
    required String cardHolderName,
  }) async {
    final token = _pci.tokenizeCardData(
      cardNumber: cardNumber,
      cvv: cvv,
      expiryMonth: expiryMonth,
      expiryYear: expiryYear,
    );

    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    final lastFour = cleaned.substring(cleaned.length - 4);
    final brand = _pci.detectCardBrand(cardNumber);

    _logger.log('Card tokenized: ****$lastFour ($brand)');

    return PaymentCard(
      id: 'card_${DateTime.now().millisecondsSinceEpoch}',
      lastFourDigits: lastFour,
      cardHolderName: cardHolderName,
      expiryMonth: expiryMonth,
      expiryYear: expiryYear,
      cardBrand: brand,
      tokenizedId: token,
    );
  }

  void _validateAmount(double amount) {
    if (amount <= 0) {
      throw const PaymentException('Amount must be positive', code: 'INVALID_AMOUNT');
    }
    if (amount > 999999.99) {
      throw const PaymentException('Amount exceeds maximum', code: 'AMOUNT_TOO_LARGE');
    }
  }

  void _validateCurrency(String currency) {
    if (!config.supportedCurrencies.contains(currency.toUpperCase())) {
      throw PaymentException(
        'Unsupported currency: $currency',
        code: 'UNSUPPORTED_CURRENCY',
      );
    }
  }
}

