class InAppPurchaseManager {
  final PaymentConfig config;
  final PaymentLogger _logger;
  final List<InAppProduct> _availableProducts = [];
  final List<TransactionResult> _purchaseHistory = [];
  final StreamController<TransactionResult> _purchaseStreamController =
      StreamController<TransactionResult>.broadcast();

  Stream<TransactionResult> get purchaseStream => _purchaseStreamController.stream;

  InAppPurchaseManager({required this.config}) : _logger = PaymentLogger(enabled: config.enableLogging);

  Future<void> initialize() async {
    _logger.log('Initializing In-App Purchase Manager');
    // In production, initialize the in_app_purchase plugin
    await _loadProducts();
  }

  Future<void> _loadProducts() async {
    // In production, query the app store for products
    // Using the in_app_purchase package
    _availableProducts.addAll([
      const InAppProduct(
        productId: 'premium_monthly',
        title: 'Premium Monthly',
        description: 'Monthly premium subscription',
        price: 9.99,
        currency: 'USD',
        subscriptionPeriod: 'P1M',
        isSubscription: true,
      ),
      const InAppProduct(
        productId: 'premium_yearly',
        title: 'Premium Yearly',
        description: 'Yearly premium subscription',
        price: 79.99,
        currency: 'USD',
        subscriptionPeriod: 'P1Y',
        isSubscription: true,
      ),
      const InAppProduct(
        productId: 'coins_100',
        title: '100 Coins',
        description: 'Pack of 100 virtual coins',
        price: 0.99,
        currency: 'USD',
      ),
      const InAppProduct(
        productId: 'coins_500',
        title: '500 Coins',
        description: 'Pack of 500 virtual coins',
        price: 3.99,
        currency: 'USD',
      ),
    ]);

    _logger.log('Loaded ${_availableProducts.length} products');
  }

  List<InAppProduct> getAvailableProducts() => List.unmodifiable(_availableProducts);

  List<InAppProduct> getSubscriptions() =>
      _availableProducts.where((p) => p.isSubscription).toList();

  List<InAppProduct> getConsumables() =>
      _availableProducts.where((p) => !p.isSubscription).toList();

  Future<TransactionResult> purchaseProduct(String productId) async {
    final product = _availableProducts.firstWhere(
      (p) => p.productId == productId,
      orElse: () => throw PaymentException('Product not found: $productId', code: 'PRODUCT_NOT_FOUND'),
    );

    _logger.log('Purchasing product: ${product.title}');

    try {
      // In production, use in_app_purchase package to initiate purchase
      await Future.delayed(const Duration(seconds: 1));

      final result = TransactionResult(
        transactionId: 'iap_${DateTime.now().millisecondsSinceEpoch}',
        status: TransactionStatus.completed,
        amount: product.price,
        currency: product.currency,
        method: PaymentMethod.inAppPurchase,
        timestamp: DateTime.now(),
        metadata: {
          'product_id': product.productId,
          'is_subscription': product.isSubscription,
        },
      );

      _purchaseHistory.add(result);
      _purchaseStreamController.add(result);

      // Server-side receipt validation
      await _validateReceipt(result.transactionId);

      _logger.log('Purchase successful: ${result.transactionId}');
      return result;
    } catch (e) {
      _logger.error('Purchase failed: $e');
      final failedResult = TransactionResult(
        transactionId: 'failed_iap_${DateTime.now().millisecondsSinceEpoch}',
        status: TransactionStatus.failed,
        amount: product.price,
        currency: product.currency,
        method: PaymentMethod.inAppPurchase,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
        errorCode: 'IAP_ERROR',
      );
      _purchaseStreamController.add(failedResult);
      return failedResult;
    }
  }

  Future<TransactionResult> restorePurchases() async {
    _logger.log('Restoring purchases');

    try {
      // In production, use in_app_purchase package to restore
      await Future.delayed(const Duration(milliseconds: 500));

      return TransactionResult(
        transactionId: 'restore_${DateTime.now().millisecondsSinceEpoch}',
        status: TransactionStatus.completed,
        amount: 0,
        currency: 'USD',
        method: PaymentMethod.inAppPurchase,
        timestamp: DateTime.now(),
        metadata: {'restored_count': _purchaseHistory.length},
      );
    } catch (e) {
      throw PaymentException('Restore failed: $e', code: 'RESTORE_ERROR');
    }
  }

  Future<bool> _validateReceipt(String transactionId) async {
    _logger.log('Validating receipt: $transactionId');
    // In production, send receipt to your server for validation
    // Server should validate with Apple/Google servers
    await Future.delayed(const Duration(milliseconds: 300));
    return true;
  }

  List<TransactionResult> getPurchaseHistory() => List.unmodifiable(_purchaseHistory);

  void dispose() {
    _purchaseStreamController.close();
  }
}

