        currency: currency,
        method: PaymentMethod.applePay,
        timestamp: DateTime.now(),
        metadata: {'wallet_type': 'apple_pay'},
      );
    } catch (e) {
      _logger.error('Apple Pay failed: $e');
      rethrow;
    }
  }

  Future<TransactionResult> payWithGooglePay({
    required double amount,
    required String currency,
    required String description,
    Map<String, dynamic>? metadata,
  }) async {
    _logger.log('Initiating Google Pay: $amount $currency');

    if (!await isGooglePayAvailable()) {
      throw const PaymentException('Google Pay not available', code: 'GOOGLE_PAY_UNAVAILABLE');
    }

    try {
      // In production:
      // 1. Create PaymentDataRequest for Google Pay
      // 2. Present Google Pay sheet
      // 3. Process the Google Pay token with Stripe
      final paymentIntentId = await _gateway.createPaymentIntent(
        amount: amount,
        currency: currency,
        metadata: {
          ...?metadata,
          'wallet_type': 'google_pay',
          'description': description,
        },
      );

      await Future.delayed(const Duration(milliseconds: 800));

      return TransactionResult(
        transactionId: paymentIntentId,
        status: TransactionStatus.completed,
        amount: amount,
        currency: currency,
        method: PaymentMethod.googlePay,
        timestamp: DateTime.now(),
        metadata: {'wallet_type': 'google_pay'},
      );
    } catch (e) {
      _logger.error('Google Pay failed: $e');
      rethrow;
    }
  }

  Map<String, dynamic> getApplePayConfig() => {
    'merchantIdentifier': config.merchantId,
    'displayName': config.merchantName,
    'countryCode': 'US',
    'currencyCode': 'USD',
    'supportedNetworks': ['visa', 'masterCard', 'amex', 'discover'],
    'merchantCapabilities': ['3DS', 'debit', 'credit'],
  };

  Map<String, dynamic> getGooglePayConfig() => {
    'provider': 'stripe',
    'environment': config.sandboxMode ? 'TEST' : 'PRODUCTION',
    'merchantInfo': {
      'merchantId': config.merchantId,
      'merchantName': config.merchantName,
    },
    'allowedPaymentMethods': [
      {
        'type': 'CARD',
        'parameters': {
          'allowedAuthMethods': ['PAN_ONLY', 'CRYPTOGRAM_3DS'],
          'allowedCardNetworks': ['VISA', 'MASTERCARD', 'AMEX', 'DISCOVER'],
        },
        'tokenizationSpecification': {
          'type': 'PAYMENT_GATEWAY',
          'parameters': {
            'gateway': 'stripe',
            'stripe:version': '2023-10-16',
            'stripe:publishableKey': config.stripePublishableKey,
          },
        },
      },
    ],
  };
}

// ============================================================
// TRANSACTION HISTORY MANAGER
// ============================================================

class TransactionHistoryManager {
  final List<TransactionResult> _transactions = [];
  final PaymentLogger _logger;

  TransactionHistoryManager({bool enableLogging = true})
      : _logger = PaymentLogger(enabled: enableLogging);

  void addTransaction(TransactionResult transaction) {
    _transactions.add(transaction);
    _logger.log('Transaction recorded: ${transaction.transactionId}');
  }

  List<TransactionResult> getAllTransactions() => List.unmodifiable(_transactions);

  List<TransactionResult> getTransactionsByStatus(TransactionStatus status) =>
      _transactions.where((t) => t.status == status).toList();

  List<TransactionResult> getTransactionsByMethod(PaymentMethod method) =>
      _transactions.where((t) => t.method == method).toList();

  List<TransactionResult> getTransactionsByDateRange(DateTime start, DateTime end) =>
      _transactions
          .where((t) => t.timestamp.isAfter(start) && t.timestamp.isBefore(end))
          .toList();

  TransactionResult? getTransactionById(String transactionId) {
    try {
      return _transactions.firstWhere((t) => t.transactionId == transactionId);
    } catch (_) {
      return null;
    }
  }

  double getTotalSpent({String? currency}) {
    final filtered = currency != null
        ? _transactions.where((t) => t.currency == currency && t.isSuccessful)
        : _transactions.where((t) => t.isSuccessful);
    return filtered.fold(0.0, (sum, t) => sum + t.amount);
  }

  Map<String, dynamic> getAnalytics() {
    final successful = _transactions.where((t) => t.isSuccessful).length;
    final failed = _transactions.where((t) => t.status == TransactionStatus.failed).length;
    final total = _transactions.length;

    return {
      'total_transactions': total,
      'successful': successful,
      'failed': failed,
      'success_rate': total > 0 ? (successful / total * 100).toStringAsFixed(1) : '0.0',
      'total_amount': getTotalSpent(),
      'methods_breakdown': _getMethodsBreakdown(),
    };
  }

  Map<String, int> _getMethodsBreakdown() {
    final breakdown = <String, int>{};
    for (final t in _transactions) {
      breakdown[t.method.name] = (breakdown[t.method.name] ?? 0) + 1;
    }
    return breakdown;
  }
}

// ============================================================
// PAYMENT LOGGER
// ============================================================

class PaymentLogger {
  final bool enabled;
  final List<LogEntry> _logs = [];

  PaymentLogger({this.enabled = true});

  void log(String message) {
    if (!enabled) return;
    final entry = LogEntry(
      level: LogLevel.info,
      message: message,
      timestamp: DateTime.now(),
    );
    _logs.add(entry);
    if (kDebugMode) {
      print('[PAYMENT INFO] ${entry.timestamp.toIso8601String()}: $message');
    }
  }

  void error(String message) {
    final entry = LogEntry(
      level: LogLevel.error,
      message: message,
      timestamp: DateTime.now(),
    );
    _logs.add(entry);
    if (kDebugMode) {
      print('[PAYMENT ERROR] ${entry.timestamp.toIso8601String()}: $message');
    }
  }

  void warning(String message) {
    if (!enabled) return;
    final entry = LogEntry(
      level: LogLevel.warning,
      message: message,
      timestamp: DateTime.now(),
    );
    _logs.add(entry);
    if (kDebugMode) {
      print('[PAYMENT WARN] ${entry.timestamp.toIso8601String()}: $message');
    }
  }

  List<LogEntry> getLogs({LogLevel? level}) {
    if (level != null) {
      return _logs.where((l) => l.level == level).toList();
    }
    return List.unmodifiable(_logs);
  }

  void clearLogs() => _logs.clear();
}

enum LogLevel { info, warning, error }

class LogEntry {
  final LogLevel level;
  final String message;
  final DateTime timestamp;

  const LogEntry({
    required this.level,
    required this.message,
    required this.timestamp,
  });
}

// ============================================================
// RETRY MANAGER
// ============================================================

class RetryManager {
  final int maxRetries;
  final Duration initialDelay;
  final double backoffMultiplier;

  const RetryManager({
    this.maxRetries = 3,
    this.initialDelay = const Duration(seconds: 1),
    this.backoffMultiplier = 2.0,
  });

  Future<T> execute<T>(Future<T> Function() operation, {bool Function(Exception)? shouldRetry}) async {
    int attempt = 0;
    Duration delay = initialDelay;

    while (true) {
      try {
        return await operation();
      } on Exception catch (e) {
        attempt++;
        if (attempt >= maxRetries) rethrow;
        if (shouldRetry != null && !shouldRetry(e)) rethrow;

        await Future.delayed(delay);
        delay = Duration(milliseconds: (delay.inMilliseconds * backoffMultiplier).round());
      }
    }
  }
}

// ============================================================
// MAIN PAYMENT SERVICE
// ============================================================

class PaymentService {
  static PaymentService? _instance;

  final PaymentConfig config;
  late final StripeGateway _gateway;
  late final InAppPurchaseManager _iapManager;
  late final MobileWalletManager _walletManager;
  late final TransactionHistoryManager _historyManager;
  late final PCIComplianceManager _pciManager;
  late final RetryManager _retryManager;
  late final PaymentLogger _logger;

  bool _initialized = false;

  PaymentService._({required this.config}) {
    _gateway = StripeGateway(config: config);
    _iapManager = InAppPurchaseManager(config: config);
    _walletManager = MobileWalletManager(config: config, gateway: _gateway);
    _historyManager = TransactionHistoryManager(enableLogging: config.enableLogging);
    _pciManager = PCIComplianceManager();
    _retryManager = const RetryManager();
    _logger = PaymentLogger(enabled: config.enableLogging);
  }

  factory PaymentService.initialize(PaymentConfig config) {
    _instance = PaymentService._(config: config);
    return _instance!;
  }

  static PaymentService get instance {
    if (_instance == null) {
      throw const PaymentException('PaymentService not initialized. Call initialize() first.',
          code: 'NOT_INITIALIZED');
    }
    return _instance!;
  }

  Future<void> setup() async {
    if (_initialized) return;

    _logger.log('Setting up Payment Service');
    await _iapManager.initialize();
    _initialized = true;
    _logger.log('Payment Service ready');
  }

  // ---- Card Payments ----

  Future<PaymentCard> addCard({
    required String cardNumber,
    required String cvv,
    required String expiryMonth,
    required String expiryYear,
    required String cardHolderName,
  }) async {
    _ensureInitialized();
    return _gateway.tokenizeCard(
      cardNumber: cardNumber,
      cvv: cvv,
      expiryMonth: expiryMonth,
      expiryYear: expiryYear,
      cardHolderName: cardHolderName,
    );
  }

  Future<TransactionResult> chargeCard({
    required PaymentCard card,
    required double amount,
    required String currency,
    String? description,
  }) async {
    _ensureInitialized();

    return _retryManager.execute(
      () => _gateway.processPayment(
        amount: amount,
        currency: currency,
        method: PaymentMethod.creditCard,
        paymentDetails: {
          'token': card.tokenizedId,
          'description': description,
        },
      ),
      shouldRetry: (e) => e is! CardDeclinedException && e is! InsufficientFundsException,
    ).then((result) {
      _historyManager.addTransaction(result);
      return result;
    });
  }

  // ---- Mobile Wallet Payments ----

  Future<TransactionResult> payWithApplePay({
    required double amount,
    required String currency,
    required String description,
  }) async {
    _ensureInitialized();
    final result = await _walletManager.payWithApplePay(
      amount: amount,
      currency: currency,
      description: description,
    );
    _historyManager.addTransaction(result);
    return result;
  }

  Future<TransactionResult> payWithGooglePay({
    required double amount,
    required String currency,
    required String description,
  }) async {
    _ensureInitialized();
    final result = await _walletManager.payWithGooglePay(
      amount: amount,
      currency: currency,
      description: description,
    );
    _historyManager.addTransaction(result);
    return result;
  }

  // ---- In-App Purchases ----

  List<InAppProduct> getAvailableProducts() {
    _ensureInitialized();
    return _iapManager.getAvailableProducts();
  }

  Future<TransactionResult> purchaseProduct(String productId) async {
    _ensureInitialized();
    final result = await _iapManager.purchaseProduct(productId);
    _historyManager.addTransaction(result);
    return result;
  }

  Future<TransactionResult> restorePurchases() async {
    _ensureInitialized();
    return _iapManager.restorePurchases();
  }

  Stream<TransactionResult> get purchaseUpdates => _iapManager.purchaseStream;

  // ---- Refunds ----

  Future<TransactionResult> refund({
    required String transactionId,
    required double amount,
    String? reason,
  }) async {
    _ensureInitialized();
    final result = await _gateway.refundPayment(
      transactionId: transactionId,
      amount: amount,
      reason: reason,
    );
    _historyManager.addTransaction(result);
    return result;
  }

  // ---- Transaction History ----

  List<TransactionResult> getTransactionHistory() => _historyManager.getAllTransactions();

  TransactionResult? getTransaction(String transactionId) =>
      _historyManager.getTransactionById(transactionId);

  Map<String, dynamic> getPaymentAnalytics() => _historyManager.getAnalytics();

  // ---- Utilities ----

  String detectCardBrand(String cardNumber) => _pciManager.detectCardBrand(cardNumber);

  String maskCardNumber(String cardNumber) => _pciManager.maskCardNumber(cardNumber);

  Future<bool> isApplePayAvailable() => _walletManager.isApplePayAvailable();

  Future<bool> isGooglePayAvailable() => _walletManager.isGooglePayAvailable();

  void _ensureInitialized() {
    if (!_initialized) {
      throw const PaymentException('PaymentService not set up. Call setup() first.',
          code: 'NOT_SETUP');
    }
  }

  void dispose() {
    _iapManager.dispose();
    _instance = null;
    _initialized = false;
  }
}

