class PaymentCardInputWidget extends StatefulWidget {
  final Function(PaymentCard card) onCardAdded;
  final Function(String error)? onError;

  const PaymentCardInputWidget({
    super.key,
    required this.onCardAdded,
    this.onError,
  });

  @override
  State<PaymentCardInputWidget> createState() => _PaymentCardInputWidgetState();
}

class _PaymentCardInputWidgetState extends State<PaymentCardInputWidget> {
  final _formKey = GlobalKey<FormState>();
  final _cardNumberController = TextEditingController();
  final _expiryController = TextEditingController();
  final _cvvController = TextEditingController();
  final _nameController = TextEditingController();

  bool _isProcessing = false;
  String _cardBrand = '';

  @override
  void dispose() {
    _cardNumberController.dispose();
    _expiryController.dispose();
    _cvvController.dispose();
    _nameController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Form(
      key: _formKey,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // Card Number
          TextFormField(
            controller: _cardNumberController,
            decoration: InputDecoration(
              labelText: 'Card Number',
              hintText: '4242 4242 4242 4242',
              prefixIcon: const Icon(Icons.credit_card),
              suffixText: _cardBrand,
              border: const OutlineInputBorder(),
            ),
            keyboardType: TextInputType.number,
            maxLength: 19,
            onChanged: (value) {
              final formatted = _formatCardNumber(value);
              if (formatted != value) {
                _cardNumberController.value = TextEditingValue(
                  text: formatted,
                  selection: TextSelection.collapsed(offset: formatted.length),
                );
              }
              setState(() {
                _cardBrand = PCIComplianceManager().detectCardBrand(value);
              });
            },
            validator: (value) {
              if (value == null || value.isEmpty) return 'Required';
              final cleaned = value.replaceAll(' ', '');
              if (cleaned.length < 13) return 'Invalid card number';
              return null;
            },
          ),
          const SizedBox(height: 16),

          // Cardholder Name
          TextFormField(
            controller: _nameController,
            decoration: const InputDecoration(
              labelText: 'Cardholder Name',
              hintText: 'John Doe',
              prefixIcon: Icon(Icons.person),
              border: OutlineInputBorder(),
            ),
            textCapitalization: TextCapitalization.words,
            validator: (value) {
              if (value == null || value.isEmpty) return 'Required';
              return null;
            },
          ),
          const SizedBox(height: 16),

          // Expiry and CVV Row
          Row(
            children: [
              Expanded(
                child: TextFormField(
                  controller: _expiryController,
                  decoration: const InputDecoration(
                    labelText: 'MM/YY',
                    hintText: '12/25',
                    prefixIcon: Icon(Icons.calendar_today),
                    border: OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: 5,
                  onChanged: (value) {
                    final formatted = _formatExpiry(value);
                    if (formatted != value) {
                      _expiryController.value = TextEditingValue(
                        text: formatted,
                        selection: TextSelection.collapsed(offset: formatted.length),
                      );
                    }
                  },
                  validator: (value) {
                    if (value == null || value.isEmpty) return 'Required';
                    if (!RegExp(r'^\d{2}/\d{2}$').hasMatch(value)) return 'Invalid format';
                    return null;
                  },
                ),
              ),
              const SizedBox(width: 16),
              Expanded(
                child: TextFormField(
                  controller: _cvvController,
                  decoration: const InputDecoration(
                    labelText: 'CVV',
                    hintText: '123',
                    prefixIcon: Icon(Icons.lock),
                    border: OutlineInputBorder(),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: 4,
                  obscureText: true,
                  validator: (value) {
                    if (value == null || value.isEmpty) return 'Required';
                    if (value.length < 3) return 'Invalid CVV';
                    return null;
                  },
                ),
              ),
            ],
          ),
          const SizedBox(height: 24),

          // Submit Button
          ElevatedButton(
            onPressed: _isProcessing ? null : _submitCard,
            style: ElevatedButton.styleFrom(
              padding: const EdgeInsets.symmetric(vertical: 16),
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
            ),
            child: _isProcessing
                ? const SizedBox(
                    height: 20,
                    width: 20,
                    child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white),
                  )
                : const Text('Add Card', style: TextStyle(fontSize: 16)),
          ),
        ],
      ),
    );
  }

  String _formatCardNumber(String input) {
    final cleaned = input.replaceAll(RegExp(r'\D'), '');
    final buffer = StringBuffer();
    for (int i = 0; i < cleaned.length && i < 16; i++) {
      if (i > 0 && i % 4 == 0) buffer.write(' ');
      buffer.write(cleaned[i]);
    }
    return buffer.toString();
  }

  String _formatExpiry(String input) {
    final cleaned = input.replaceAll(RegExp(r'\D'), '');
    if (cleaned.length >= 3) {
      return '${cleaned.substring(0, 2)}/${cleaned.substring(2, cleaned.length > 4 ? 4 : cleaned.length)}';
    }
    return cleaned;
  }

  Future<void> _submitCard() async {
    if (!_formKey.currentState!.validate()) return;

    setState(() => _isProcessing = true);

    try {
      final expiryParts = _expiryController.text.split('/');
      final card = await PaymentService.instance.addCard(
        cardNumber: _cardNumberController.text,
        cvv: _cvvController.text,
        expiryMonth: expiryParts[0],
        expiryYear: expiryParts[1],
        cardHolderName: _nameController.text,
      );

      widget.onCardAdded(card);
    } on PaymentException catch (e) {
      widget.onError?.call(e.message);
    } catch (e) {
      widget.onError?.call('An unexpected error occurred');
    } finally {
      if (mounted) setState(() => _isProcessing = false);
    }
  }
}

