class _PaymentCheckoutWidgetState extends State<PaymentCheckoutWidget> {
  bool _isProcessing = false;
  PaymentMethod? _selectedMethod;
  bool _applePayAvailable = false;
  bool _googlePayAvailable = false;

  @override
  void initState() {
    super.initState();
    _checkAvailableMethods();
  }

  Future<void> _checkAvailableMethods() async {
    try {
      final applePay = await PaymentService.instance.isApplePayAvailable();
      final googlePay = await PaymentService.instance.isGooglePayAvailable();
      if (mounted) {
        setState(() {
          _applePayAvailable = applePay;
          _googlePayAvailable = googlePay;
        });
      }
    } catch (_) {}
  }

  @override
  Widget build(BuildContext context) {
    return Card(
      elevation: 4,
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      child: Padding(
        padding: const EdgeInsets.all(20),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          mainAxisSize: MainAxisSize.min,
          children: [
            // Amount Display
            Text(
              'Total: ${_formatCurrency(widget.amount, widget.currency)}',
              style: Theme.of(context).textTheme.headlineSmall?.copyWith(
                fontWeight: FontWeight.bold,
              ),
              textAlign: TextAlign.center,
            ),
            const SizedBox(height: 8),
            Text(
              widget.description,
              style: Theme.of(context).textTheme.bodyMedium?.copyWith(color: Colors.grey[600]),
              textAlign: TextAlign.center,
            ),
            const Divider(height: 32),

            // Payment Methods
            Text('Payment Method', style: Theme.of(context).textTheme.titleMedium),
            const SizedBox(height: 12),

            // Credit Card Option
            _buildMethodTile(
              method: PaymentMethod.creditCard,
              icon: Icons.credit_card,
              title: 'Credit / Debit Card',
              subtitle: 'Pay with your card',
            ),
            const SizedBox(height: 8),

            // Apple Pay
            if (_applePayAvailable) ...[
              _buildMethodTile(
                method: PaymentMethod.applePay,
                icon: Icons.apple,
                title: 'Apple Pay',
                subtitle: 'Fast and secure',
              ),
              const SizedBox(height: 8),
            ],

            // Google Pay
            if (_googlePayAvailable) ...[
              _buildMethodTile(
                method: PaymentMethod.googlePay,
                icon: Icons.g_mobiledata,
                title: 'Google Pay',
                subtitle: 'Fast and secure',
              ),
              const SizedBox(height: 8),
            ],

            const SizedBox(height: 16),

            // Pay Button
            ElevatedButton(
              onPressed: _selectedMethod != null && !_isProcessing ? _processPayment : null,
              style: ElevatedButton.styleFrom(
                padding: const EdgeInsets.symmetric(vertical: 16),
                backgroundColor: Colors.green[700],
                foregroundColor: Colors.white,
                shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
              ),
              child: _isProcessing
                  ? const Row(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        SizedBox(
                          height: 20,
                          width: 20,
                          child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white),
                        ),
                        SizedBox(width: 12),
                        Text('Processing...', style: TextStyle(fontSize: 16)),
                      ],
                    )
                  : Text(
                      'Pay ${_formatCurrency(widget.amount, widget.currency)}',
                      style: const TextStyle(fontSize: 16, fontWeight: FontWeight.bold),
                    ),
            ),

            const SizedBox(height: 12),

            // Security badge
            Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Icon(Icons.lock, size: 14, color: Colors.grey[500]),
                const SizedBox(width: 4),
                Text(
                  'Secured by PCI DSS Compliance',
                  style: TextStyle(fontSize: 12, color: Colors.grey[500]),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildMethodTile({
    required PaymentMethod method,
    required IconData icon,
    required String title,
    required String subtitle,
  }) {
    final isSelected = _selectedMethod == method;
    return InkWell(
      onTap: () => setState(() => _selectedMethod = method),
      borderRadius: BorderRadius.circular(8),
      child: Container(
        padding: const EdgeInsets.all(12),
        decoration: BoxDecoration(
          border: Border.all(
            color: isSelected ? Colors.blue : Colors.grey[300]!,
            width: isSelected ? 2 : 1,
          ),
          borderRadius: BorderRadius.circular(8),
          color: isSelected ? Colors.blue.withOpacity(0.05) : null,
        ),
        child: Row(
          children: [
            Icon(icon, size: 28, color: isSelected ? Colors.blue : Colors.grey[700]),
            const SizedBox(width: 12),
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(title, style: TextStyle(
                    fontWeight: FontWeight.w600,
                    color: isSelected ? Colors.blue : null,
                  )),
                  Text(subtitle, style: TextStyle(fontSize: 12, color: Colors.grey[500])),
                ],
              ),
            ),
            if (isSelected) const Icon(Icons.check_circle, color: Colors.blue),
          ],
        ),
      ),
    );
  }

  Future<void> _processPayment() async {
    if (_selectedMethod == null) return;

    setState(() => _isProcessing = true);

    try {
      TransactionResult result;

      switch (_selectedMethod!) {
        case PaymentMethod.applePay:
          result = await PaymentService.instance.payWithApplePay(
            amount: widget.amount,
            currency: widget.currency,
            description: widget.description,
          );
          break;
        case PaymentMethod.googlePay:
          result = await PaymentService.instance.payWithGooglePay(
            amount: widget.amount,
            currency: widget.currency,
            description: widget.description,
          );
          break;
        case PaymentMethod.creditCard:
        case PaymentMethod.debitCard:
          // Show card input dialog
          if (mounted) {
            final card = await _showCardInputDialog();
            if (card == null) {
              setState(() => _isProcessing = false);
              return;
            }
            result = await PaymentService.instance.chargeCard(
              card: card,
              amount: widget.amount,
              currency: widget.currency,
              description: widget.description,
            );
          } else {
            return;
          }
          break;
        default:
          throw PaymentException('Unsupported method: ${_selectedMethod!.name}');
      }

      widget.onPaymentComplete(result);
    } on PaymentException catch (e) {
      widget.onPaymentError?.call(e.message);
    } catch (e) {
      widget.onPaymentError?.call('Payment failed: $e');
    } finally {
      if (mounted) setState(() => _isProcessing = false);
    }
  }

  Future<PaymentCard?> _showCardInputDialog() async {
    PaymentCard? result;
    await showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
      ),
      builder: (context) => Padding(
        padding: EdgeInsets.only(
          left: 20,
          right: 20,
          top: 20,
          bottom: MediaQuery.of(context).viewInsets.bottom + 20,
        ),
        child: PaymentCardInputWidget(
          onCardAdded: (card) {
            result = card;
            Navigator.of(context).pop();
          },
          onError: (error) {
            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(content: Text(error), backgroundColor: Colors.red),
            );
          },
        ),
      ),
    );
    return result;
  }

  String _formatCurrency(double amount, String currency) {
    final symbols = {'USD': '\$', 'EUR': '€', 'GBP': '£'};
    final symbol = symbols[currency] ?? currency;
    return '$symbol${amount.toStringAsFixed(2)}';
  }
}

